const contracts = $input.all().map(i => i.json);
const alerts = [];
for (const c of contracts) {
  const hasExisting = parseInt(c.existing_pursuits) > 0;
  alerts.push({
    contract_id: c.id, contract_name: c.name, client: c.client, piid: c.piid,
    ceiling: c.ceiling, fy_revenue: c.fy_revenue, pop_end: c.pop_end,
    days_until_expiry: c.days_until_expiry, urgency: c.urgency, pm: c.pm, naics: c.naics,
    existing_pursuits: parseInt(c.existing_pursuits), has_active_pursuit: hasExisting,
    recommended_action: hasExisting
      ? `Verify pursuit for ${c.name} recompete is active and capture plan is at Gate 2+`
      : `INITIATE: Create recompete pursuit for ${c.name} — expires in ${c.days_until_expiry} days`,
    alert_type: 'recompete_warning', generated_at: new Date().toISOString()
  });
}
return alerts.map(a => ({json: a}));
